class Solution:
    def maxFreeTime(self, eventTime, k, startTime, endTime):
        n = len(startTime)
        gaps = [startTime[0]]
        for i in range(1, n):
            gaps.append(startTime[i] - endTime[i - 1])
        gaps.append(eventTime - endTime[-1])
        window = k + 1
        best = 0
        m = len(gaps)
        for i in range(0, m - window + 1):
            total = sum(gaps[i:i + window])
            if total > best:
                best = total
        return best

