class Solution:
    def maxFreeTime(self, eventTime, k, startTime, endTime):
        n = len(startTime)
        gaps = [startTime[0]]
        for i in range(1, n):
            gaps.append(startTime[i] - endTime[i - 1])
        gaps.append(eventTime - endTime[-1])
        window = k + 1
        cur = sum(gaps[:window])
        best = cur
        for i in range(window, len(gaps)):
            cur += gaps[i] - gaps[i - window]
            if cur > best:
                best = cur
        return best

