var maxFreeTime = function(eventTime, k, startTime, endTime) {
    const n = startTime.length;
    const gaps = [startTime[0]];
    for (let i = 1; i < n; i++) gaps.push(startTime[i] - endTime[i - 1]);
    gaps.push(eventTime - endTime[n - 1]);
    const window = k + 1;
    let cur = 0;
    for (let i = 0; i < window; i++) cur += gaps[i];
    let best = cur;
    for (let i = window; i < gaps.length; i++) {
        cur += gaps[i] - gaps[i - window];
        if (cur > best) best = cur;
    }
    return best;
};
